  account_details: { fields: { detailId, accountId(fk:accounts), industry, size, website, description, foundedYear, headquarters } },
  account_settings: { fields: { settingId, accountId(fk:accounts), preferredLocale, timezone, dateFormat, currencyCode, notifyOnOrderChange, notifyOnInvoiceOverdue, autoApproveOrders } },
