  account_health_scores: { fields: { scoreId, accountId(fk:accounts), score, trend, calculatedAt, riskLevel, notes } },

  // Orders domain (10)
  orders: { fields: { orderId, accountId(fk:accounts), contactId, status, totalCents, currency, createdAt, approvedAt, fulfilledAt, notes } },
  order_line_items: { fields: { lineItemId, orderId(fk:orders), productId(fk:products), productName, quantity, unitPriceCents, discountCents, taxCents, totalCents } },
  order_fulfillments: { fields: { fulfillmentId, orderId(fk:orders), status, fulfilledAt, warehouseId, carrierId, notes } },
  order_returns: { fields: { returnId, orderId(fk:orders), reason, status, refundCents, requestedAt, processedAt } },
  shipments: { fields: { shipmentId, orderId(fk:orders), carrier, trackingNumber, status, shippedAt, deliveredAt, shippingCostCents, originAddress, destinationAddress } },
  shipment_items: { fields: { shipmentItemId, shipmentId(fk:shipments), lineItemId(fk:order_line_items), quantityShipped } },
  shipment_tracking: { fields: { trackingEventId, shipmentId(fk:shipments), event, location, timestamp, description } },
  delivery_confirmations: { fields: { confirmationId, shipmentId(fk:shipments), confirmedBy, confirmedAt, signatureRequired, photoUrl, notes } },
  order_status_history: { fields: { historyId, orderId(fk:orders), fromStatus, toStatus, changedBy, changedAt, reason } },
  order_approvals: { fields: { approvalId, orderId(fk:orders), approverId, status, approverRole, approvedAt, comments } },

  // Financial domain (7)
  invoices: { fields: { invoiceId, accountId(fk:accounts), orderId(fk:orders), invoiceNumber, amountCents, taxCents, totalCents, status, issuedAt, dueAt, paidAt } },
  invoice_line_items: { fields: { invoiceLineId, invoiceId(fk:invoices), description, quantity, unitPriceCents, totalCents, taxRatePct } },
  payments: { fields: { paymentId, invoiceId(fk:invoices), accountId(fk:accounts), amountCents, method, status, processedAt, referenceNumber } },
  payment_methods: { fields: { paymentMethodId, accountId(fk:accounts), type, isDefault, lastFour, expiryMonth, expiryYear, billingName, status } },
  credit_notes: { fields: { creditNoteId, invoiceId(fk:invoices), accountId(fk:accounts), amountCents, reason, status, issuedAt } },
  tax_records: { fields: { taxRecordId, invoiceId(fk:invoices), taxType, jurisdiction, ratePct, amountCents } },
  billing_cycles: { fields: { cycleId, accountId(fk:accounts), period, startDate, endDate, status, totalCents } },

  // Support domain (5)
  support_cases: { fields: { caseId, accountId(fk:accounts), orderId(fk:orders), subject, priority, status, openedAt, resolvedAt, assignedTo } },
  case_comments: { fields: { commentId, caseId(fk:support_cases), authorId, body, isInternal, createdAt } },
  case_escalations: { fields: { escalationId, caseId(fk:support_cases), escalatedBy, escalatedTo, reason, status, createdAt, resolvedAt } },
  sla_policies: { fields: { slaId, name, priorityLevel, responseTimeHours, resolutionTimeHours, isActive } },
  support_assignments: { fields: { assignmentId, caseId(fk:support_cases), agentId, role, assignedAt, status } },

  // Product domain (5)
  products: { fields: { productId, name, sku, categoryId(fk:product_categories), description, isActive, launchDate } },
  product_categories: { fields: { categoryId, name, parentId(fk:product_categories), description } },
  product_pricing: { fields: { pricingId, productId(fk:products), tier, unitPriceCents, currency, minQuantity, effectiveFrom, effectiveTo } },
