  // Compliance domain (5)
  compliance_reviews: { fields: { reviewId, accountId(fk:accounts), orderId(fk:orders), reviewType, status, reviewerId, openedAt, closedAt, findings } },
  regulatory_flags: { fields: { flagId, accountId(fk:accounts), orderId(fk:orders), regulation, severity, description, raisedAt, resolvedAt } },
  audit_trails: { fields: { auditId, accountId(fk:accounts), entityType, entityId, action, performedBy, performedAt, changes, ipAddress } },
