import { withDb } from "./db.mjs";

// Enterprise schema: 40 tables with 3NF normalization, FKs, CHECK constraints.

// Module-level flag: drop and recreate schema exactly once per process so each
// test run starts with a clean slate (avoids duplicate-key failures on re-runs).
let schemaInitialized = false;

export async function ensureSchema(client) {
	if (schemaInitialized) return;
	schemaInitialized = true;

	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();

	// Drop every table (CASCADE handles any lingering FK constraints) so we
	// start with a clean slate on each test process run.
	for (const t of [...gen.tableNames].reverse()) {
		await client.query(`DROP TABLE IF EXISTS ${t} CASCADE`);
	}

	// Recreate all 40 tables.
	await gen.ensureSchema(client);

	// ── ALTER TABLE: primary-key defaults ──────────────────────────────────────
	// order_line_items.line_item_id — test inserts without providing this PK;
	// give it a UUID default so Postgres generates it automatically.
	await client.query(`
		ALTER TABLE order_line_items
		ALTER COLUMN line_item_id SET DEFAULT gen_random_uuid()::TEXT
	`);

	// ── ALTER TABLE: relax NOT NULL on columns the test omits ─────────────────
	// The test inserts (order_id, product_name, quantity, unit_price_cents) only.
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN product_id  DROP NOT NULL`);
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN total_cents  DROP NOT NULL`);

	// ── ALTER TABLE: add columns the test references but the generated DDL lacks ─
	// The test INSERT into invoices includes a currency column not in the entity def.
	await client.query(`ALTER TABLE invoices ADD COLUMN IF NOT EXISTS currency TEXT`);

	// ── ALTER TABLE: schema-evolution addition (preferred_payment_method) ──────
	await client.query(`
		ALTER TABLE accounts
		ADD COLUMN IF NOT EXISTS preferred_payment_method VARCHAR(50)
		  CHECK (preferred_payment_method IN ('credit_card', 'wire_transfer', 'ach', 'paypal'))
	`);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}
